// SPLASH
window.addEventListener('load', () => {
  setTimeout(() => {
    document.getElementById('splash').classList.add('hidden');
    triggerHeroReveal();
  }, 1700);
});

// THEME TOGGLE
const themeBtn = document.getElementById('themeToggle');
let isDark = true;
themeBtn.addEventListener('click', () => {
  isDark = !isDark;
  document.documentElement.setAttribute('data-theme', isDark ? 'dark' : 'light');
  themeBtn.textContent = isDark ? '☀️' : '🌙';
});

// HAMBURGER
const hamburger = document.getElementById('hamburger');
const mobileMenu = document.getElementById('mobileMenu');
hamburger.addEventListener('click', () => {
  hamburger.classList.toggle('open');
  mobileMenu.classList.toggle('open');
});
function closeMobile() {
  hamburger.classList.remove('open');
  mobileMenu.classList.remove('open');
}

// SCROLL PROGRESS
window.addEventListener('scroll', () => {
  const pct = (window.scrollY / (document.body.scrollHeight - window.innerHeight)) * 100;
  document.getElementById('progress').style.width = pct + '%';
});

// SCROLL REVEAL
function triggerHeroReveal() {
  document.querySelectorAll('#hero .reveal').forEach((el, i) => {
    setTimeout(() => el.classList.add('visible'), i * 100);
  });
}
const observer = new IntersectionObserver((entries) => {
  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
}, { threshold: 0.12 });
document.querySelectorAll('.reveal').forEach(el => observer.observe(el));

// CARD GLOW
document.querySelectorAll('.skill-card, .project-card').forEach(card => {
  card.addEventListener('mousemove', e => {
    const r = card.getBoundingClientRect();
    card.style.setProperty('--mx', (e.clientX - r.left) + 'px');
    card.style.setProperty('--my', (e.clientY - r.top) + 'px');
  });
});

// EXPAND TIMELINE
function toggleExpand(btn) {
  const panel = btn.nextElementSibling;
  panel.classList.toggle('open');
  btn.textContent = panel.classList.contains('open') ? 'Hide details ↑' : 'Show details ↓';
}

// RESUME DOWNLOAD (embedded PDF)
document.getElementById('resumeBtn').addEventListener('click', function(e) {
  e.preventDefault();
  const link = document.createElement('a');
  link.href = 'data:application/pdf;base64,';
  link.download = 'Aitha_Ramakrishna_Resume.pdf';
  link.click();
});

// ANIMATED BACKGROUND
(function() {
  const canvas = document.getElementById('bg-canvas');
  const ctx = canvas.getContext('2d');
  let W, H, particles;
  const isMobile = window.innerWidth < 768;
  const PARTICLE_COUNT = isMobile ? 30 : 70;

  function resize() { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; }
  function randomParticle() {
    return { x: Math.random()*W, y: Math.random()*H, vx:(Math.random()-0.5)*0.4, vy:(Math.random()-0.5)*0.4, r:Math.random()*2+0.5, alpha:Math.random()*0.5+0.1 };
  }
  function init() { resize(); particles = Array.from({length:PARTICLE_COUNT}, randomParticle); }
  function drawGradientMesh() {
    const dark = document.documentElement.getAttribute('data-theme') !== 'light';
    const g1 = ctx.createRadialGradient(W*0.15,H*0.25,0,W*0.15,H*0.25,W*0.4);
    g1.addColorStop(0, dark?'rgba(99,179,237,0.06)':'rgba(99,130,237,0.08)'); g1.addColorStop(1,'transparent');
    ctx.fillStyle=g1; ctx.fillRect(0,0,W,H);
    const g2 = ctx.createRadialGradient(W*0.85,H*0.6,0,W*0.85,H*0.6,W*0.45);
    g2.addColorStop(0, dark?'rgba(159,122,234,0.06)':'rgba(120,80,200,0.06)'); g2.addColorStop(1,'transparent');
    ctx.fillStyle=g2; ctx.fillRect(0,0,W,H);
    const g3 = ctx.createRadialGradient(W*0.5,H*0.9,0,W*0.5,H*0.9,W*0.35);
    g3.addColorStop(0, dark?'rgba(104,211,145,0.04)':'rgba(50,180,100,0.05)'); g3.addColorStop(1,'transparent');
    ctx.fillStyle=g3; ctx.fillRect(0,0,W,H);
  }
  function draw() {
    ctx.clearRect(0,0,W,H); drawGradientMesh();
    ctx.lineWidth=0.4;
    for(let i=0;i<particles.length;i++) {
      for(let j=i+1;j<particles.length;j++) {
        const dx=particles[i].x-particles[j].x, dy=particles[i].y-particles[j].y;
        const dist=Math.sqrt(dx*dx+dy*dy);
        if(dist<140){const a=(1-dist/140)*0.08;ctx.strokeStyle=`rgba(99,179,237,${a})`;ctx.beginPath();ctx.moveTo(particles[i].x,particles[i].y);ctx.lineTo(particles[j].x,particles[j].y);ctx.stroke();}
      }
    }
    particles.forEach(p=>{
      ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=`rgba(150,180,255,${p.alpha})`;ctx.fill();
      p.x+=p.vx; p.y+=p.vy;
      if(p.x<-10)p.x=W+10; if(p.x>W+10)p.x=-10;
      if(p.y<-10)p.y=H+10; if(p.y>H+10)p.y=-10;
    });
    requestAnimationFrame(draw);
  }
  window.addEventListener('resize', resize);
  init(); draw();
})();